const config = $('Get Agent Config').item.json;
const historyData = $('Get Session History').item.json;
const body = $('Webhook Trigger').item.json.body;

// 1. Remplacer les variables dans le prompt système
let systemPrompt = config.systemPrompt;
const variables = typeof config.variables === 'string' ? config.variables : JSON.stringify(config.variables);
systemPrompt = systemPrompt.replace('{variables}', variables);

// 2. Construire l'historique des messages pour OpenAI
const messages = [];

if (historyData && historyData.messages) {
  historyData.messages.forEach(msg => {
    messages.push({
      role: msg.role === 'assistant' ? 'assistant' : 'user',
      content: msg.content
    });
  });
}

// Ajouter le message actuel de l'utilisateur
messages.push({
  role: 'user',
  content: body.message
});

// 3. Préparer le payload OpenAI
const openaiPayload = {
  model: "gpt-4o-mini",
  messages: [
    {
      role: "system",
      content: systemPrompt
    },
    ...messages
  ],
  temperature: 0.7
};

return {
  json: {
    sessionId: body.sessionId,
    slug: body.slug,
    platform: body.platform || 'web',
    openaiPayload: openaiPayload,
    currentMessage: body.message
  }
};

const rawResponse = $('OpenAI Chat API').item.json.choices[0].message.content;
const inputData = $('Merge Prompt & History').item.json;

let reply = rawResponse;
let isQualified = false;
let leadData = null;

// Regex pour détecter [QUALIFIED: {json}]
const match = rawResponse.match(/\[QUALIFIED:\s*(\{.*?\})\s*\]/s);
if (match) {
  try {
    leadData = JSON.parse(match[1]);
    isQualified = true;
    // Nettoyer le tag de la réponse finale
    reply = rawResponse.replace(/\[QUALIFIED:\s*\{.*?\}\s*\]/s, '').trim();
  } catch (e) {
    console.error("Erreur de parsing du JSON de qualification", e);
  }
}

return {
  json: {
    sessionId: inputData.sessionId,
    slug: inputData.slug,
    platform: inputData.platform,
    reply: reply,
    isQualified: isQualified,
    leadData: leadData,
    userMessage: inputData.currentMessage
  }
};

